/* RevSlider 5.x — slideanims extension stub
 * Provides a minimal animateSlide that fades the incoming slide in.
 * Parameters: (t, pe, opt, nextSlide, currentSlide, bg, speed, masterTimeline)
 */
;(function($, undefined) {
  "use strict";
  var _R = $.fn.revolution;
  $.extend(true, _R, {
    animateSlide: function(t, pe, opt, nextSlide, currentSlide, bg, speed, masterTimeline) {
      // Ensure we always have a valid timeline to return
      if (!masterTimeline) masterTimeline = new punchgs.TimelineLite();
      if (nextSlide) {
        masterTimeline.add(
          punchgs.TweenLite.to(nextSlide, 0.8, { autoAlpha: 1, zIndex: 20 }),
          0
        );
      }
      return masterTimeline;
    },
    animateNewSlide: function() {},
    animateOldSlide: function() {},
    getSlideAnimationObj: function() { return {}; }
  });
})(jQuery);
